arguments.file_text:
@if (Products is null || !Products.Any())
{
    <div class="alert alert-info text-center">
        <p class="mb-0">No products found matching your criteria.</p>
    </div>
}
else
{
    <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
        @foreach (var product in Products)
        {
            <div class="col">
                <ProductCard Product="product"
                             OnSelected="HandleProductSelected"
                             OnAddToCart="HandleAddToCart" />
            </div>
        }
    </div>
}

@code {
    [Parameter, EditorRequired]
    public List<Product> Products { get; set; } = new();

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private async Task HandleAddToCart(Product product)
    {
        await OnAddToCart.InvokeAsync(product);
    }
}

@if (TotalPages > 1)
{
    <nav aria-label="Product catalog pagination" class="mt-4">
        <ul class="pagination justify-content-center">
            <li class="page-item @(CurrentPage <= 1 ? "disabled" : "")">
                <button class="page-link" @onclick="@(() => GoToPage(CurrentPage - 1))" disabled="@(CurrentPage <= 1)">
                    Previous
                </button>
            </li>
            @for (int i = 1; i <= TotalPages; i++)
            {
                var pageNum = i;
                <li class="page-item @(pageNum == CurrentPage ? "active" : "")">
                    <button class="page-link" @onclick="@(() => GoToPage(pageNum))">@pageNum</button>
                </li>
            }
            <li class="page-item @(CurrentPage >= TotalPages ? "disabled" : "")">
                <button class="page-link" @onclick="@(() => GoToPage(CurrentPage + 1))" disabled="@(CurrentPage >= TotalPages)">
                    Next
                </button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter]
    public int CurrentPage { get; set; }

    [Parameter]
    public int TotalPages { get; set; }

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != CurrentPage)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }
}

@page "/catalog"
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-4">Product Catalog</h3>

@if (_error is not null)
{
    <div class="alert alert-danger">
        <strong>Error:</strong> @_error
    </div>
}

<div class="row">
    <div class="col-md-3">
        <CatalogFilters Categories="_categories"
                        OnFilterApplied="HandleFilterApplied"
                        OnFilterCleared="HandleFilterCleared" />
    </div>
    <div class="col-md-9">
        @if (_loading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else if (_result is not null)
        {
            <CatalogToolbar SortBy="@_sortBy"
                            TotalCount="_result.TotalCount"
                            Page="_result.Page"
                            PageSize="_result.PageSize"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="_result.Items"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />

            var totalPages = (int)Math.Ceiling((double)_result.TotalCount / _result.PageSize);
            <CatalogPagination CurrentPage="_currentPage"
                               TotalPages="totalPages"
                               OnPageChanged="HandlePageChanged" />
        }
    </div>
</div>

@code {
    private List<string>? _categories;
    private PagedResult<Product>? _result;
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int PageSize = 12;
    private bool _loading = true;
    private string? _error;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            _loading = true;
            _error = null;

            var categoriesTask = _categories is null
                ? ProductService.GetCategoriesAsync()
                : Task.FromResult(_categories);
            var searchTask = ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            _categories = await categoriesTask;
            _result = await searchTask;
        }
        catch (Exception ex)
        {
            _error = $"Failed to load products. {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandleFilterCleared()
    {
        _filter = new ProductFilter(null, null, null, false);
        _currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await LoadDataAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Add to cart logic would go here
        return Task.CompletedTask;
    }
}

